const config = $('Config - WF4').first().json;
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);
const aliases = $items('Google Sheets - Produkt_Aliase lesen').map(i => i.json);
let input = {};
try { input = $('Form Trigger - Nayax Name eingeben').first().json; } catch(e) {}
try { const x = $('Execute Workflow Trigger - aus Verkaufsworkflow').first().json; if (Object.keys(x || {}).length) input = x; } catch(e) {}

function clean(v){return String(v ?? '').replace(/\n/g,' ').replace(/\s+/g,' ').trim();}
function norm(v){return clean(v).toLowerCase().replace(/&/g,'und').replace(/\+/g,'plus').replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue').replace(/ß/g,'ss').replace(/[^a-z0-9]/g,'');}
function mdbNorm(v){const s=clean(v).replace(',','.'); return /^\d+\.0+$/.test(s)?String(parseInt(s,10)):s;}
function toks(v){return [...new Set((norm(v).match(/[a-z]+|[0-9]+/g)||[]).filter(t=>t.length>=2))];}
function parseNayax(raw){ const t=clean(raw); const m=t.match(/^(.*?)\s*\((\d+)\s*=\s*([0-9]+(?:[.,][0-9]+)?)\)\s*$/); return m ? {label:clean(m[1]),mdb_code:mdbNorm(m[2]),sale_price_eur:clean(m[3]).replace(',','.')} : {label:t,mdb_code:'',sale_price_eur:''}; }
function isActive(row){ const a=clean(row.active).toUpperCase(); return ['TRUE','1','JA','YES'].includes(a) && !clean(row.valid_to_datetime || row.valid_to); }
function score(p,q){ const qq=norm(q); const txt=[p.product_key,p.internal_product_name,p.nayax_product_name,p.mdb_code,p.machine_id].map(clean).join(' '); const pp=norm(txt); let s=0; if(qq&&pp===qq)s+=95; if(qq&&pp.includes(qq))s+=70; const pt=toks(txt); s+=toks(q).filter(t=>pt.includes(t)).length*12; if(isActive(p)||clean(p.active)==='')s+=5; return Math.min(s,99); }

const searchRaw=clean(input['Nayax Produktname oder Suchbegriff']||input.nayax_product_name||input.raw_product_name||input.product_name||input.search);
const parsed=parseNayax(searchRaw);
const search=clean(input.product_label||parsed.label||searchRaw);
const machineId=clean(input.machine_id||config.default_machine_id);
const actualMdb=mdbNorm(input.actual_mdb_code||input.new_mdb_code||input.mdb_code||parsed.mdb_code);
const expectedMdb=mdbNorm(input.expected_mdb_code||input.old_mdb_code);
const suggestedProductKey=clean(input.product_key||input.suggested_product_key);
const settlement=clean(input.settlement_datetime_gmt||input.sale_datetime_utc);
const detectedReason=clean(input.detected_reason||'');
const defaultChangeType=clean(input.suggested_change_type)||(expectedMdb&&actualMdb&&expectedMdb!==actualMdb?'Produkt auf anderen MDB-Slot umziehen':'Produkt im Slot austauschen');
if(!search && !suggestedProductKey) throw new Error('Kein Suchbegriff und kein product_key vorhanden.');

const aliasHits=aliases.filter(a=>{const al=clean(a.alias_name||a.source_item); return al && norm(al) && (norm(al)===norm(search)||norm(search).includes(norm(al))||norm(al).includes(norm(search)));});
let ranked=products.map(p=>{let s=score(p,search); if(suggestedProductKey&&clean(p.product_key)===suggestedProductKey)s+=100; if(aliasHits.some(a=>clean(a.product_key)===clean(p.product_key)))s+=45; if(actualMdb&&clean(p.machine_id)===machineId&&mdbNorm(p.mdb_code)===actualMdb)s+=15; return {product:p,score:Math.min(s,99)};}).filter(x=>clean(x.product.product_key)&&x.score>=Number(config.min_candidate_score||45)).sort((a,b)=>b.score-a.score).slice(0,5);
if(!ranked.length && suggestedProductKey) ranked=products.filter(p=>clean(p.product_key)===suggestedProductKey).map(p=>({product:p,score:99}));

const active=products.filter(p=>clean(p.machine_id)===machineId && isActive(p));
const activeOnActualMdb=actualMdb?active.filter(p=>mdbNorm(p.mdb_code)===actualMdb):[];
const activeOnExpectedMdb=expectedMdb?active.filter(p=>mdbNorm(p.mdb_code)===expectedMdb):[];
const activeSameProduct=suggestedProductKey?active.filter(p=>clean(p.product_key)===suggestedProductKey):(ranked.length?active.filter(p=>clean(p.product_key)===clean(ranked[0].product.product_key)):[]);
const baseRows=suggestedProductKey?products.filter(p=>clean(p.product_key)===suggestedProductKey && !clean(p.product_slot_id) && !clean(p.machine_id) && !clean(p.mdb_code)): (ranked.length?products.filter(p=>clean(p.product_key)===clean(ranked[0].product.product_key) && !clean(p.product_slot_id) && !clean(p.machine_id) && !clean(p.mdb_code)) : []);

const candText=ranked.length?ranked.map((x,i)=>`${i+1} = ${clean(x.product.product_key)} | ${clean(x.product.internal_product_name||x.product.nayax_product_name)} | MDB ${mdbNorm(x.product.mdb_code)||'-'} | Treffer ${x.score}%`).join('\n'):'Keine Kandidaten gefunden. Bitte abbrechen und Produkt zuerst im Stammdatenprozess anlegen.';
const slotText=[
  activeOnActualMdb.length?`Aktiv auf MDB neu/ist ${actualMdb}: ${activeOnActualMdb.map(p=>`${clean(p.product_key)} / ${clean(p.internal_product_name||p.nayax_product_name)}`).join('; ')}`:(actualMdb?`Aktiv auf MDB neu/ist ${actualMdb}: keine aktive Zeile gefunden`:'MDB neu/ist: nicht erkannt'),
  activeOnExpectedMdb.length?`Aktiv auf MDB alt/erwartet ${expectedMdb}: ${activeOnExpectedMdb.map(p=>`${clean(p.product_key)} / ${clean(p.internal_product_name||p.nayax_product_name)}`).join('; ')}`:(expectedMdb?`Aktiv auf MDB alt/erwartet ${expectedMdb}: keine aktive Zeile gefunden`:'MDB alt/erwartet: nicht angegeben'),
  activeSameProduct.length?`Aktive Slots desselben Produkts: ${activeSameProduct.map(p=>`MDB ${mdbNorm(p.mdb_code)} (${clean(p.product_key)})`).join(', ')}`:'Aktive Slots desselben Produkts: keine oder unklar',
  baseRows.length?`Slotlose WF2-Basiszeilen fuer Produkt: ${baseRows.length}`:'Slotlose WF2-Basiszeilen fuer Produkt: keine'
].join('\n');

const defaultValidFrom=settlement||new Date().toISOString();
const formInfo=['MDB-/Produktzuordnung prüfen','',`Quelle: ${detectedReason||(input.source||'manueller Start')}`,`Maschine: ${machineId}`,`Suchbegriff/Nayax-Name: ${searchRaw||search}`,`Bereinigter Produktname: ${search}`,`MDB alt/erwartet: ${expectedMdb||'(leer)'}`,`MDB neu/ist: ${actualMdb||'(leer)'}`,`Gültig ab Vorschlag: ${defaultValidFrom}`,'','Slotstatus:',slotText,'','Produktkandidaten:',candText,'','Hinweis:','WF4 ergänzt vorhandene slotlose WF2-Produktzeilen, wenn genau eine passende Basiszeile existiert.'].join('\n');

return [{json:{
  source:clean(input.source||'manual_or_sales_workflow'),
  detected_reason:detectedReason,
  machine_id:machineId,
  search_raw:searchRaw,
  search_label:search,
  parsed_mdb_code:parsed.mdb_code,
  parsed_sale_price_eur:parsed.sale_price_eur,
  expected_mdb_code:expectedMdb,
  actual_mdb_code:actualMdb,
  default_valid_from_utc:defaultValidFrom,
  default_change_type_de:defaultChangeType,
  default_current_machine_qty:clean(input.current_machine_qty||input.current_machine_qty_after_change),
  default_machine_capacity:clean(input.machine_capacity),
  default_target_stock:clean(input.target_stock),
  default_min_stock:clean(input.min_stock),
  candidates:ranked.map((x,i)=>({number:String(i+1),score:x.score,product_key:clean(x.product.product_key),internal_product_name:clean(x.product.internal_product_name),nayax_product_name:clean(x.product.nayax_product_name),mdb_code:mdbNorm(x.product.mdb_code),machine_id:clean(x.product.machine_id),product_slot_id:clean(x.product.product_slot_id),sale_price_eur:clean(x.product.sale_price_eur)})),
  active_on_actual_mdb:activeOnActualMdb,
  active_on_expected_mdb:activeOnExpectedMdb,
  active_same_product:activeSameProduct,
  base_product_rows:baseRows,
  form_info:formInfo
}}];

const prepared = $('Code - Produktwechsel vorbereiten').first().json;
const form = $input.first().json;
const config = $('Config - WF4').first().json;
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);

function clean(v){return String(v ?? '').replace(/\n/g,' ').replace(/\s+/g,' ').trim();}
function norm(v){return clean(v).toLowerCase().replace(/&/g,'und').replace(/\+/g,'plus').replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue').replace(/ß/g,'ss').replace(/[^a-z0-9]/g,'');}
function mdbNorm(v){const s=clean(v).replace(',','.'); return /^\d+\.0+$/.test(s)?String(parseInt(s,10)):s;}
function iso(v){const d=new Date(clean(v)||new Date().toISOString()); if(Number.isNaN(d.getTime())) throw new Error('Gültig ab UTC ist kein valides Datum/Zeitformat: '+clean(v)); return d.toISOString();}
function stamp(v){return clean(v).replace(/[-:]/g,'').replace(/\.\d+Z$/,'Z');}
function psid(machineId,mdb,pk,from){return `PS_${clean(machineId)}_${mdbNorm(mdb)}_${clean(pk)}_${stamp(from)}`;}
function first(...vals){return vals.map(clean).find(v=>v!=='')||'';}
function isActive(row){const a=clean(row.active).toUpperCase(); return ['TRUE','1','JA','YES'].includes(a) && !clean(row.valid_to_datetime || row.valid_to);}
function hasSlotData(row){return !!(clean(row.product_slot_id)||clean(row.machine_id)||clean(row.mdb_code)||clean(row.valid_from_datetime)||clean(row.valid_from));}
function productName(row){return first(row.internal_product_name,row.nayax_product_name,row.product_key);}
function warning(type,severity,message,productKey=''){warningRows.push({created_at:now,type,severity,machine_id:machineId,product_key:productKey||selectedProductKey,nayax_product_name:selectedName,message,resolved:'FALSE',change_id:changeId});}

const now=new Date().toISOString();
const machineId=clean(prepared.machine_id||config.default_machine_id);
const oldMdb=mdbNorm(form['MDB-Code alt']||prepared.expected_mdb_code);
const newMdb=mdbNorm(form['MDB-Code neu']||prepared.actual_mdb_code||prepared.parsed_mdb_code);
const validFromUtc=iso(form['Gültig ab UTC']||prepared.default_valid_from_utc);
const note=clean(form.Notiz);
const choice=clean(form.Produktwahl).toUpperCase();
const changeTypeDe=clean(form['Änderungsart']);
const map={ [norm('Produkt im Slot austauschen')]:'REPLACE_SLOT', [norm('Produkt auf anderen MDB-Slot umziehen')]:'MOVE_PRODUCT', [norm('Produkt zusätzlich auf weiteren Slot legen')]:'ADD_ADDITIONAL_SLOT', [norm('Produkt aus Slot entfernen')]:'REMOVE_PRODUCT', [norm('Nur Stammdaten korrigieren')]:'CORRECT_METADATA', [norm('Bestand korrigieren ohne Produktwechsel')]:'STOCK_CORRECTION' };
const changeTypeInternal=map[norm(changeTypeDe)];
if(!changeTypeInternal) throw new Error('Unbekannte Änderungsart. Bitte exakt einen vorgeschlagenen deutschen Wert verwenden.');

const selected=prepared.candidates.find(c=>c.number===choice);
const isRejected=norm(form.Freigabe)!=='ja'||choice==='ABLEHNEN'||choice==='REJECT';
const closeRows=[],newRows=[],baseRowUpdates=[],warningRows=[],logRows=[];
const selectedProductKey=selected?clean(selected.product_key):'';
const selectedName=selected?first(selected.internal_product_name,selected.nayax_product_name):'';
const changeId=`CHG_${machineId}_${oldMdb||'NA'}_${newMdb||'NA'}_${selectedProductKey||'NO_PRODUCT'}_${stamp(validFromUtc)}`;

if(isRejected){
  logRows.push({change_id:changeId,changed_at_utc:now,source:prepared.source,detected_reason:prepared.detected_reason,machine_id:machineId,old_mdb_code:oldMdb,new_mdb_code:newMdb,new_product_key:selectedProductKey,new_product_name:selectedName,change_type_de:changeTypeDe,change_type_internal:changeTypeInternal,valid_from_utc:validFromUtc,status:'abgelehnt',action_required:'FALSE',notes:note||'Im Formular abgelehnt.'});
  return [{json:{closeRows,newRows,baseRowUpdates,warningRows,logRows,summary:{status:'abgelehnt',change_id:changeId}}}];
}

if(!newMdb && ['REPLACE_SLOT','MOVE_PRODUCT','ADD_ADDITIONAL_SLOT'].includes(changeTypeInternal)) throw new Error('MDB-Code neu fehlt.');
if(!selectedProductKey && !['REMOVE_PRODUCT','STOCK_CORRECTION'].includes(changeTypeInternal)) throw new Error('Kein Produkt ausgewählt.');

const activeRows=products.filter(p=>clean(p.machine_id)===machineId && isActive(p));
const activeOnNew=activeRows.filter(p=>mdbNorm(p.mdb_code)===newMdb);
const activeOnOld=oldMdb?activeRows.filter(p=>mdbNorm(p.mdb_code)===oldMdb):[];
const activeSameProduct=activeRows.filter(p=>clean(p.product_key)===selectedProductKey);
const exactActive=activeRows.filter(p=>mdbNorm(p.mdb_code)===newMdb && clean(p.product_key)===selectedProductKey);
const baseRows=products.filter(p=>clean(p.product_key)===selectedProductKey && !hasSlotData(p));

function close(row,reason){
  return {product_slot_id:clean(row.product_slot_id),product_key:clean(row.product_key),machine_id:clean(row.machine_id||machineId),mdb_code:mdbNorm(row.mdb_code),active:'FALSE',valid_to_datetime:validFromUtc,valid_to:validFromUtc,last_change_id:changeId,notes:[clean(row.notes),reason,note].filter(Boolean).join(' | ')};
}

function slotFields(product,mdb){
  return {
    product_slot_id:psid(machineId,mdb,product.product_key,validFromUtc),
    product_key:product.product_key,
    machine_id:machineId,
    mdb_code:mdbNorm(mdb),
    nayax_product_name:product.nayax_product_name||product.internal_product_name,
    internal_product_name:product.internal_product_name||product.nayax_product_name,
    sale_price_eur:product.sale_price_eur||'',
    valid_from_datetime:validFromUtc,
    valid_from:validFromUtc,
    valid_to_datetime:'',
    valid_to:'',
    active:'TRUE',
    replenishment_status:'',
    min_stock:clean(form.Mindestbestand),
    target_stock:clean(form.Zielbestand),
    current_machine_qty:clean(form['Aktueller Maschinenbestand nach Änderung']),
    machine_capacity:clean(form['Slot-Kapazität']),
    stock_source:'WF4_MDB_Produktwechsel',
    last_change_id:changeId,
    notes:note
  };
}

function setSlot(product,mdb){
  if(exactActive.length){
    warning('WF4_SLOT_ALREADY_ACTIVE','info',`Aktive Slotzeile existiert bereits fuer machine_id=${machineId}, mdb=${mdbNorm(mdb)}, product_key=${selectedProductKey}. Es wurde keine neue Produktzeile erzeugt.`);
    return;
  }

  if(baseRows.length > 1){
    warning('WF4_DUPLICATE_BASE_PRODUCT_ROWS','error',`Mehrere slotlose WF2-Produktzeilen fuer product_key=${selectedProductKey} gefunden. Bitte zuerst bereinigen; WF4 erzeugt keine weitere Dublette.`);
    return;
  }

  const fields=slotFields(product,mdb);
  if(baseRows.length === 1){
    baseRowUpdates.push(fields);
  } else {
    newRows.push(fields);
  }
}

if(changeTypeInternal==='MOVE_PRODUCT'){
  const rowsToClose=oldMdb?activeSameProduct.filter(r=>mdbNorm(r.mdb_code)===oldMdb):activeSameProduct.filter(r=>mdbNorm(r.mdb_code)!==newMdb);
  for(const r of rowsToClose) closeRows.push(close(r,'WF4: Produkt auf anderen MDB-Slot umgezogen.'));
  setSlot(selected,newMdb);
}

if(changeTypeInternal==='REPLACE_SLOT'){
  for(const r of activeOnNew.filter(r=>clean(r.product_key)!==selectedProductKey)) closeRows.push(close(r,'WF4: Produkt im Slot ausgetauscht.'));
  setSlot(selected,newMdb);
}

if(changeTypeInternal==='ADD_ADDITIONAL_SLOT'){
  const blockers=activeOnNew.filter(r=>clean(r.product_key)!==selectedProductKey);
  if(blockers.length){
    warning('WF4_TARGET_SLOT_OCCUPIED','error',`MDB ${newMdb} ist bereits aktiv belegt. Fuer zusätzlichen Slot bitte anderen MDB-Code wählen oder Produkttausch verwenden.`);
  } else {
    setSlot(selected,newMdb);
  }
}

if(changeTypeInternal==='REMOVE_PRODUCT'){
  const rows=activeOnNew.length?activeOnNew:activeOnOld;
  for(const r of rows) closeRows.push(close(r,'WF4: Produkt aus Slot entfernt.'));
}

if(changeTypeInternal==='CORRECT_METADATA') warning('WF4_METADATA_CORRECTION_NOT_AUTOMATED','warning','Nur Stammdaten korrigieren gewählt. Diese Version protokolliert nur.');
if(changeTypeInternal==='STOCK_CORRECTION') warning('WF4_STOCK_CORRECTION_REQUESTED','action_required','Bestand korrigieren ohne Produktwechsel gewählt. Bitte Bestandskorrekturworkflow verwenden.');

for(const r of closeRows) if(!clean(r.product_slot_id)) warning('MISSING_PRODUCT_SLOT_ID','error',`Alte Produktzeile konnte nicht sicher geschlossen werden, weil product_slot_id fehlt. product_key=${r.product_key}, mdb=${r.mdb_code}`,r.product_key);

const hasError=warningRows.some(w=>clean(w.severity)==='error');
if(hasError){
  newRows.length=0;
  baseRowUpdates.length=0;
}

logRows.push({change_id:changeId,changed_at_utc:now,source:prepared.source,detected_reason:prepared.detected_reason,machine_id:machineId,old_mdb_code:oldMdb,new_mdb_code:newMdb,old_product_key:closeRows.map(r=>r.product_key).join('; '),new_product_key:selectedProductKey,new_product_name:selectedName,change_type_de:changeTypeDe,change_type_internal:changeTypeInternal,valid_from_utc:validFromUtc,status:hasError?'mit_fehler':'verarbeitet',action_required:warningRows.length?'TRUE':'FALSE',notes:note});

return [{json:{closeRows,newRows,baseRowUpdates,warningRows,logRows,summary:{status:hasError?'mit_fehler':'verarbeitet',change_id:changeId,close_rows:closeRows.length,new_rows:newRows.length,base_row_updates:baseRowUpdates.length,warnings:warningRows.length}}}];
